#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
CI MAXN=1e4+5;
vector<int> g[MAXN];
int n,m,dis[MAXN],f[MAXN][3];
/*
1.
f[u][0]表示u点自己管
f[u][1]表示u点儿子管
f[u][2]表示u点父亲管
2.
f[u][0]+=min(min(f[s][0],f[s][1]),f[s][2]);//选最少的
f[u][1]=min(f[u][1],f[s][0]-min(f[s][0],f[s][1]));
f[u][2]+=min(f[s][0],f[s][1]);//选最少的
3.
f[u][0]=dis[u];选，花了dis[u]
f[u][1]=inf;不选，不确定花多少
f[u][2]=0;不选，不确定花多少
*/                     
void dfs(int u,int fa)
{
	f[u][0]=dis[u];
	f[u][1]=inf;
	f[u][2]=0;
	FOI(s,g[u])
	{
		if(s==fa)continue;
		dfs(s,u);
		f[u][0]+=min(min(f[s][0],f[s][1]),f[s][2]);
		f[u][1]=min(f[u][1],f[s][0]-min(f[s][0],f[s][1]));
		f[u][2]+=min(f[s][0],f[s][1]);
	}
	f[u][1]+=f[u][2];
}
signed main(void)
{
	ios::sync_with_stdio(0);
	cin.tie(0);cout.tie(0);
	cin>>n;
	FOR(i,1,n)
	{
		int u;
		cin>>u>>dis[u]>>m;
		FOR(j,1,m)
		{
			int v;
			cin>>v;
    		g[u].pb(v);
			g[v].pb(u);
		}
	}
	dfs(1,0);
	cout<<min(f[1][0],f[1][1]);
	return false;
}
